import { moduleMetadata } from '@storybook/angular';
import { PfTextareaComponent } from './textarea.component';
const meta = {
    title: 'Composants/Textarea',
    component: PfTextareaComponent,
    tags: ['autodocs'],
    parameters: {
        docs: {
            description: {
                component: "Champ de saisie multi-lignes. Mêmes patterns que Input (label, hint, error, ARIA) avec `rows` configurable et resize vertical par défaut.",
            },
        },
    },
    decorators: [
        moduleMetadata({ imports: [PfTextareaComponent] }),
        (storyFn) => {
            const story = storyFn();
            return { ...story, template: `<div style="width: 480px;">${story.template}</div>` };
        },
    ],
    argTypes: {
        rows: { control: { type: 'number', min: 1, max: 20 } },
        required: { control: 'boolean' },
        disabled: { control: 'boolean' },
    },
    args: {
        label: 'Description',
        placeholder: 'Décrivez votre demande en quelques lignes…',
        rows: 4,
    },
    render: (args) => ({
        props: args,
        template: `<pf-textarea
      [label]="label"
      [hint]="hint"
      [error]="error"
      [placeholder]="placeholder"
      [rows]="rows"
      [required]="required"
      [disabled]="disabled"
      [value]="value"
      (valueChange)="value = $event"
    ></pf-textarea>`,
    }),
};
export default meta;
export const Default = {};
export const WithHint = {
    args: { hint: 'Maximum 500 caractères.' },
};
export const Required = { args: { required: true } };
export const WithError = {
    args: { value: '', error: 'La description est obligatoire.', required: true },
};
export const Disabled = {
    args: { disabled: true, value: 'Texte verrouillé qui ne peut pas être modifié.' },
};
